#include <stdio.h>
#include <stdlib.h>

#define RADIX 255

static long range = 1;
static long fraction = 0;
static int cc[2000000];

static void emit_digit(int d){ putchar((unsigned char)((d+1)&0xFF)); }
static void normalize_encoder(void){
    while(range<RADIX){
        long d=fraction/RADIX;
        fraction=(fraction-d*RADIX)*RADIX;
        range*=RADIX;
        emit_digit((int)d);
    }
}
static void put_bit(int ctx,int bit){
    normalize_encoder();
    int idx=ctx*2;
    int c0=cc[idx], c1=cc[idx+1];
    long split=range*(c0+1)/(c0+c1+2);
    if(bit==0) range=split;
    else { fraction+=split; range-=split; }
    cc[idx+bit]++;
}
static void encode_integer(int start,int ctx,int value){
    long result=(long)value+(1L<<start);
    int tmp=0;
    while((1L<<(tmp+1))<=result) tmp++;
    int ctx2=ctx*99;
    fprintf(stderr,"enc value=%d result=%ld tmp=%d start=%d\n", value, result, tmp, start);
    for(int t=start+1;t<=tmp;t++){
        fprintf(stderr,"enc stop0 tmp=%d ctx=%d\n", t, t+ctx2);
        put_bit(t+ctx2,0);
    }
    fprintf(stderr,"enc stop1 tmp=%d ctx=%d\n", tmp+1, tmp+1+ctx2);
    put_bit(tmp+1+ctx2,1);
    for(int i=tmp-1;i>=0;i--){
        int b=(int)((result>>i)&1);
        fprintf(stderr,"enc pay bit=%d ctx=%d i=%d\n", b, ctx, i);
        put_bit(ctx,b);
    }
}
static void finish(void){ normalize_encoder(); for(int i=0;i<8;i++) emit_digit(0); }
int main(void){
    encode_integer(9,0,7);
    finish();
    return 0;
}
