#include <stdio.h>
#include <stdlib.h>

#define W for (i=0;i<tmp;i++)

int i;
int radix = 255;
int fraction;
long range = 1;
int tmp;
int cc[1000000];

int gc() {
  int c = getchar();
  if (c == EOF) { fprintf(stderr, "EOF in gc\n"); exit(1); }
  fprintf(stderr, "gc read %d\n", c);
  return (int)(unsigned char)c;
}

int get_bit(int ctx) {
  if ( range < radix ) {
    range *= radix;
    fraction *= radix;
    fraction += gc()-1;
  }
  int *counts = cc + ctx * 2;
  int split = range * -~*counts / (*counts + counts[ 1 ] + 2);
  int the_bit = fraction >= split;
  fraction -= split*the_bit;
  range = the_bit ? range-split : split;
  counts[ the_bit ]++;
  fprintf(stderr, "dec get_bit ctx=%d bit=%d range=%ld fraction=%d split=%d\n", ctx, the_bit, range, fraction, split);
  return the_bit;
}

int get_integer(int tmp_arg, int ctx) {
  int subtract_it = 1<<tmp_arg;
  int result_ans = 1;
  int local_tmp = tmp_arg;
  int orig_ctx = ctx;
  ctx*=99;
  while (!get_bit(++local_tmp+ctx));
  local_tmp--;
  tmp = local_tmp;
  fprintf(stderr, "dec get_integer start=%d stop_tmp=%d payload_bits=%d\n", tmp_arg, local_tmp+1, local_tmp);
  W {
    int b = get_bit(orig_ctx);
    result_ans = result_ans*2 | b;
    fprintf(stderr, "dec payload bit=%d result_ans=%d\n", b, result_ans);
  }
  fprintf(stderr, "dec get_integer returning %d\n", result_ans - subtract_it);
  return result_ans - subtract_it;
}

int main(void) {
  int v = get_integer(9,0);
  printf("decoded=%d\n", v);
  return 0;
}
